const mongoose = require("mongoose");

const BugSchema = new mongoose.Schema(
  {
    title: {
      type: String,
      required: true,
    },

    description: {
      type: String,
      required: true,
    },

    company: {
      type: mongoose.Schema.Types.ObjectId,
      ref: "User",
      required: true,
    },

    submittedBy: {
      type: mongoose.Schema.Types.ObjectId,
      ref: "User",
      required: true,
    },

    /* REQUIRED for Sandbox */
    testUrl: {
      type: String,
      required: true,
    },

    payload: {
      type: String,
      required: true,
    },

    /* Optional fields */
    severity: {
      type: String,
      enum: ["low", "medium", "high", "critical"],
      default: "low",
    },

    steps: {
      type: String,
      default: "",
    },

    attachments: {
      type: Array,
      default: [],
    },

    status: {
      type: String,
      enum: ["submitted", "approved", "rejected", "duplicate"],
      default: "submitted",
    },

    duplicateOf: {
      type: mongoose.Schema.Types.ObjectId,
      ref: "Bug",
      default: null,
    },

    reward: {
      type: Number,
      default: 0,
    },

    /* Sandbox result history */
    sandboxResults: {
      type: Array,
      default: [],
    },
  },
  { timestamps: true }
);

module.exports = mongoose.model("Bug", BugSchema);
